//! The **eval-tier rule catalogue**: the computation-backed certificate and
//! toHOL rules admitted by [`CoreEval`], generated by the
//! `eval_rules!` macro (the same lockstep emission pattern as core's
//! `core_rules!` ‚Äî manifest and admits from ONE source list, so they cannot
//! drift).
//!
//! Moved here from `covalence-core` (stage E2 of
//! `notes/vibes/handoff/defs-out-of-core.md`): these rules ARE trusted ‚Äî each
//! carries its `Soundness:` docstring ‚Äî but their trust is *declared at the
//! eval tier*: only a `Thm<CoreEval>` (or a language that chooses to admit
//! them) depends on them; `Thm<CoreLang>` never does. The orphan rule binds
//! `Rule` impls for the locally-owned `CoreEval` to this crate, which is what
//! lets the certificate dispatch tables (`super::certs`) sit NEXT TO the
//! catalogue definitions and the native `covalence-pure-eval` `CanonRule`s
//! they must agree with ‚Äî the auditability goal of the move.
//!
//! Two sections, both feeding the SAME manifest/admits emission:
//! - `raw { ‚Ä¶ }` ‚Äî rules whose `Concl` is an arbitrary `Expr<Ty = bool>`
//!   (symbolic toHOL equations / `IsThm` certificates), implemented
//!   `Rule<L>` for **every** `L: Language` (the gate is still `admits` on the
//!   rule's own `TypeId`, so a language admits one only by enumerating it).
//! - `canon { ‚Ä¶ }` ‚Äî [`covalence_pure::CanonRule`] ops admitted for
//!   [`covalence_pure::canon`] evaluation (no `Rule` impl; the op's own
//!   `TypeId` is the gate identity).

use std::any::TypeId;

use covalence_pure::{
    App, CanonRule as _, Eqn, Error as PureError, LangMeta, Language, Manifest, Rule, RuleMeta,
    RuleRecord, Val,
};
use covalence_types::{Bytes, Int, Nat};

use covalence_core::seam::{CoreProp, IsThm, Lit};
use covalence_core::{Ctx, Error, Term, TermSpec};

use crate::certs;
use crate::lang::CoreEval;
use crate::tohol_ops::{
    NatAddEqE, ToHolBytes, ToHolBytesE, ToHolInt, ToHolIntE, ToHolNat, ToHolNatE, nat_add_eq_expr,
};

pub use crate::tohol_ops::HolApp;

/// The eval-side sequent floor (mirrors core's `seq`): the conclusion and
/// every hypothesis must be well-typed at kind `bool`, then wrap into the
/// `IsThm` proposition. [`covalence_core::Thm::from_pure`] re-runs the same
/// check on landing, so this is defense-in-depth at mint time, not the only
/// gate.
fn seq(hyps: Ctx, concl: Term) -> Result<CoreProp, Error> {
    let ty = concl.type_of()?;
    if !ty.is_bool() {
        return Err(Error::NotBool(ty));
    }
    for h in hyps.iter() {
        let hty = h.type_of()?;
        if !hty.is_bool() {
            return Err(Error::NotBool(hty));
        }
    }
    Ok(App(IsThm, (Val(hyps), Val(concl))))
}

/// Lower a typed [`Error`] into pure's stringly-typed `RuleFailed`.
fn to_pure(e: Error) -> PureError {
    PureError::RuleFailed(e.to_string())
}

/// One rule ‚áí ZST + `Rule<L>` impl + admits arm + `RuleRecord`, in lockstep
/// from one source list (see the module docs for the two sections).
macro_rules! eval_rules {
    (
        raw { $( $(#[$rd:meta])* $R:ident($rin:ty) -> $rc:ty = |$rp:pat_param, $rl:pat_param| $rb:block )+ }
        canon { $( $K:ident ),+ $(,)? }
    ) => {
        $(
            $(#[$rd])*
            #[derive(Clone, Copy)]
            pub struct $R;

            impl<L: Language> Rule<L> for $R {
                type Input = $rin;
                type Concl = $rc;
                fn decide(
                    self,
                    input: Self::Input,
                    lang: &L,
                ) -> core::result::Result<$rc, PureError> {
                    let ($rp, $rl) = (input, lang);
                    $rb
                }
            }
        )+

        /// The static TCB manifest for [`CoreEval`] ‚Äî one [`RuleRecord`] per
        /// eval-tier rule (raw and canon sections alike), emitted from the
        /// same source lists as [`eval_admits`]. The single parent is
        /// [`covalence_core::seam::CORE_MANIFEST`] (embedded by value), so
        /// `tree(CoreEval)` ‚Äî the whole tower down to the base `Builtins` ‚Äî
        /// is readable from this one static. Golden:
        /// `docs/deps/eval-manifest.txt`.
        pub static EVAL_MANIFEST: Manifest = Manifest {
            ty: TypeId::of::<CoreEval>(),
            extends: &[covalence_core::seam::CORE_MANIFEST],
            admits: &[
                $( RuleRecord { ty: TypeId::of::<$R>(), metadata: RuleMeta }, )+
                $( RuleRecord { ty: TypeId::of::<$K>(), metadata: RuleMeta }, )+
            ],
            metadata: LangMeta,
        };

        /// The direct-rule admits predicate for [`CoreEval`], emitted from
        /// the same lists as [`EVAL_MANIFEST`]: `true` exactly for the
        /// eval-tier rule TypeIds (inherited HOL rules are delegated to
        /// [`covalence_core::seam::core_admits`] by `CoreEval::admits`).
        pub fn eval_admits(r: TypeId) -> bool {
            $( r == TypeId::of::<$R>() )||+
            $( || r == TypeId::of::<$K>() )+
        }

        /// Untrusted name projection of [`EVAL_MANIFEST`] (same order, 1:1) ‚Äî
        /// for the `docs/deps/eval-manifest.txt` golden. Identity is always
        /// the `TypeId`.
        #[cfg(test)]
        pub(crate) fn eval_rule_names() -> Vec<(&'static str, TypeId)> {
            vec![
                $( (stringify!($R), TypeId::of::<$R>()), )+
                $( (stringify!($K), TypeId::of::<$K>()), )+
            ]
        }
    };
}

eval_rules! {
    // ================= The toHOL tier (symbolic conclusions) =================
    //
    // These rules' conclusions are NOT `CoreProp`: they are base propositions
    // over symbolic HOL-term expressions (`toHOL` denotations, never-constructed
    // canonical terms). They mint via `covalence_pure::apply` directly; every
    // `decide` below is deterministic and total on its input.

    raw {
    /// TRANSITIONAL (dies with the kernel `Nat` literals ‚Äî see `SKELETONS.md`):
    /// `‚ä¢ toHOL n = Val(‚åún‚åù)` ‚Äî reify a `toHOL`-denoted natural to today's
    /// literal-numeral `Term`.
    ///
    /// ## Soundness
    ///
    /// While the kernel `Nat` literals exist, the literal numeral IS the
    /// kernel's canonical HOL term for the natural `n` (the same denotational
    /// commitment the legacy literal reducer documents: literals denote the
    /// standard values). `toHOL n` denotes exactly that term, so the equation
    /// holds by definition of the denotation. At literal-deletion time this
    /// rule is deleted and the permanent structural rules (`toHOL 0 = ‚åúzero‚åù`,
    /// `toHOL (n+1) = S (toHOL n)`) take over; only the reify target flips.
    ToHolNatVal(Nat) -> Eqn<ToHolNatE, Val<Term>> = |n, _| {
        let t = Term::nat_lit(n.clone());
        Ok(Eqn(App(ToHolNat, Val(n)), Val(t)))
    }

    /// `‚ä¢ (Val f, Val x) = Val((f, x))` at the `(Term, Term)` product sort ‚Äî
    /// fuse a tuple of ground leaves into one ground tuple leaf. The bridge
    /// between `cong_pair` (which produces tuples **of** `Val`s) and
    /// [`covalence_pure::canon`] (whose evaluated redex takes its whole input
    /// as one `Val` **of** a tuple).
    ///
    /// ## Soundness
    ///
    /// Both sides denote the same pair `(f, x)` of the product sort ‚Äî tuple
    /// expressions denote tuples of their components' denotations, and `Val`
    /// leaves denote themselves. The two shapes are one value read two ways;
    /// no computation, no new equalities between distinct values.
    PairVal((Term, Term)) -> Eqn<(Val<Term>, Val<Term>), Val<(Term, Term)>> = |(f, x), _| {
        Ok(Eqn((Val(f.clone()), Val(x.clone())), Val((f, x))))
    }

    /// The nat.add computation-backed derivability certificate:
    /// `‚ä¢ IsThm(‚àÖ, ‚åúnat.add (toHOL a) (toHOL b) = toHOL (a + b)‚åù)`, where the
    /// sum is computed natively by the [`covalence_pure_eval::NatAdd`]
    /// [`CanonRule`](covalence_pure::CanonRule) and the HOL equation stays
    /// **symbolic** (its numeral leaves are `toHOL` denotations ‚Äî never
    /// materialized).
    ///
    /// ## Soundness (the existence-without-construction contract)
    ///
    /// The soundness contract of every such rule (its docstring obligation):
    /// for every native value `b` there *exists* a HOL term `[b]` such that
    /// the defining properties are derivable in pure HOL ‚Äî
    /// existence-without-construction, the same principle as "a standard
    /// theorem means a derivation exists". Concretely here: `[n]` is the
    /// numeral `S^n(Z)`, and whenever the native addition computes
    /// `a + b = c`, the HOL equation `nat.add [a] [b] = [c]` is derivable in
    /// pure HOL by `c` primitive-recursive unfoldings of `nat.add`'s
    /// definitional equations on the numerals ‚Äî the derivation exists for
    /// every `(a, b)`, and this rule is a certified shortcut that never adds
    /// strength. The rule derives its whole conclusion from the input pair
    /// (no caller-supplied conclusion), so it is sound on ALL inputs.
    NatAddCert((Nat, Nat)) -> App<IsThm, (Val<Ctx>, NatAddEqE)> = |(a, b), _| {
        // `NatAdd` is total (addition never refuses), so the `None` arm is
        // unreachable; refuse (never mint) if it ever fires.
        let sum = covalence_pure_eval::NatAdd
            .eval(&(a.clone(), b.clone()))
            .ok_or(covalence_pure::Error::NoMatch)?;
        Ok(App(IsThm, (Val(Ctx::new()), nat_add_eq_expr(a, b, sum))))
    }

    /// TRANSITIONAL (dies with the kernel `Int` literals): `‚ä¢ toHOL i =
    /// Val(‚åúi‚åù)` ‚Äî reify a `toHOL`-denoted integer to today's literal `Term`.
    ///
    /// ## Soundness
    ///
    /// Same argument as [`ToHolNatVal`]: while the kernel `Int` literals
    /// exist, the literal IS the kernel's canonical HOL term for the integer
    /// `i`, and `toHOL i` denotes exactly that term, so the equation holds by
    /// definition of the denotation. At literal-deletion time this rule dies
    /// and the permanent structural rule (`toHOL i = int.mk (toHOL p) (toHOL
    /// n)`) takes over; only the reify target flips.
    ToHolIntVal(Int) -> Eqn<ToHolIntE, Val<Term>> = |i, _| {
        let t = Term::int_lit(i.clone());
        Ok(Eqn(App(ToHolInt, Val(i)), Val(t)))
    }

    /// TRANSITIONAL (dies with the kernel `Blob` literals): `‚ä¢ toHOL bs =
    /// Val(‚åúbs‚åù)` ‚Äî reify a `toHOL`-denoted bytestring to today's literal
    /// `Term`.
    ///
    /// ## Soundness
    ///
    /// Same argument as [`ToHolNatVal`], at the `bytes` carrier: the `Blob`
    /// literal IS the canonical HOL term for the bytestring while it exists.
    /// At literal-deletion time the permanent structural rules (`toHOL [] =
    /// ‚åúnil‚åù`, `toHOL (b:rest) = cons (toHOL b) (toHOL rest)`) take over.
    ToHolBytesVal(Bytes) -> Eqn<ToHolBytesE, Val<Term>> = |bs, _| {
        let t = Term::blob(bs.clone());
        Ok(Eqn(App(ToHolBytes, Val(bs)), Val(t)))
    }

    // ------------- The per-family computation-backed certificates -----------
    //
    // Concl = `CoreProp` (the `IsThm` sequent shape), minted through the same
    // well-typedness floor as core's sequent rules; the equation is built
    // and computed by the audited dispatch in `super::certs` (canonical
    // `TermSpec::ptr_id` tables ‚Üí `covalence-pure-eval` `CanonRule` evals ‚Äî
    // the enumerable computation-TCB record in the `Builtins` manifest).
    //
    // ## Soundness (the existence-without-construction contract)
    //
    // The soundness contract of every such rule (its docstring obligation):
    // for every native value `b` there *exists* a HOL term `[b]` such that
    // the defining properties are derivable in pure HOL ‚Äî
    // existence-without-construction, the same principle as "a standard
    // theorem means a derivation exists". Whenever the native computation
    // yields `op(args) = r`, the HOL equation `op ‚åúargs‚åù = ‚åúr‚åù` is derivable
    // in pure HOL from the op's definitional equations on the literal
    // denotations; each family rule is a certified shortcut that never adds
    // strength. Every rule derives its whole conclusion from the input
    // (selector + native args; the selector only fires on the canonical
    // catalogue handle, by pointer identity), so it is sound on ALL inputs.

    /// `nat.*` arithmetic / comparison certificate:
    /// `‚ä¢ IsThm(‚àÖ, ‚åúop ‚åúargs‚åù = ‚åúop(args)‚åù‚åù)` for the canonical `nat.pred` /
    /// `add` / `mul` / `sub` / `div` / `mod` / `pow` / `shl` / `shr` /
    /// `bitAnd` / `bitOr` / `bitXor` / `le` / `lt` handles.
    ///
    /// ## Soundness
    ///
    /// The family contract above, plus the FORCED edge-case conventions
    /// (pinned by `covalence-pure-eval`'s semantics suite):
    /// saturating `pred`/`sub`; `n / 0 = 0` and **`n mod 0 = n`** (forced by
    /// `nat.mod`'s let-style body `Œªn m. n - (n/m)*m`, which at `m = 0`
    /// evaluates to `n`; any other value would let definitional unfolding
    /// derive `‚ä¢ False`); detectably-unrepresentable results REFUSE (`None`
    /// from the fallible `CanonRule::eval` ‚Äî oversize `pow` exponents on a
    /// base ‚â• 2, oversize `shl` shifts on a non-zero operand; `shr` is total).
    NatArithCert((TermSpec, Vec<Lit>)) -> CoreProp = |(spec, args), _| {
        certs::nat_arith(&spec, &args)
            .and_then(|eq| seq(Ctx::new(), eq))
            .map_err(to_pure)
    }

    /// The kernel-primitive successor certificate:
    /// `‚ä¢ IsThm(‚àÖ, ‚åúsucc ‚åún‚åù = ‚åún + 1‚åù‚åù)` (`succ` is `TermKind::Succ`, not
    /// a catalogue spec, hence no `TermSpec` selector).
    ///
    /// ## Soundness
    ///
    /// The family contract above: `succ` on the literal denotations is
    /// exactly native `n + 1` (the `nat.succ` pure-eval `CanonRule`).
    SuccCert(Nat) -> CoreProp = |n, _| {
        certs::succ_concl(&n)
            .and_then(|eq| seq(Ctx::new(), eq))
            .map_err(to_pure)
    }

    /// `int.*` arithmetic / comparison certificate for the canonical
    /// `int.succ` / `pred` / `neg` / `abs` / `sgn` / `add` / `mul` / `sub` /
    /// `div` / `mod` / `le` / `lt` handles (`abs : int ‚Üí nat`).
    ///
    /// ## Soundness
    ///
    /// The family contract above, plus the FORCED conventions: truncating
    /// division, remainder takes the dividend's sign, and `a / 0 = 0`,
    /// **`a mod 0 = a`** ‚Äî forced by `int.div`/`int.mod`'s let-style
    /// catalogue bodies exactly as for `nat.mod`.
    IntArithCert((TermSpec, Vec<Lit>)) -> CoreProp = |(spec, args), _| {
        certs::int_arith(&spec, &args)
            .and_then(|eq| seq(Ctx::new(), eq))
            .map_err(to_pure)
    }

    /// `bytes.*` certificate for the canonical `bytes.cat` / `consNat` /
    /// `len` / `at` / `slice` handles.
    ///
    /// ## Soundness
    ///
    /// The family contract above, plus the conventions: the `consNat`
    /// operand is reduced mod 256; an out-of-bounds `at` index reads 0;
    /// `slice (start, len)` saturates to the buffer.
    BytesCert((TermSpec, Vec<Lit>)) -> CoreProp = |(spec, args), _| {
        certs::bytes_cert(&spec, &args)
            .and_then(|eq| seq(Ctx::new(), eq))
            .map_err(to_pure)
    }

    /// The fixed-width `uN`/`sN` certificate, keyed by the canonical
    /// `defs::int_ops` registry (arithmetic / bitwise / shifts / comparisons
    /// / `zext`/`sext` casts / nat-int conversions).
    ///
    /// ## Soundness
    ///
    /// The family contract above, plus the conventions: arithmetic wraps mod
    /// `2^width`; signed/unsigned `div`/`rem`/`shr`/comparisons read the
    /// operand's tag; shift amounts are taken mod width; and `x / 0 = 0`,
    /// **`x rem 0 = x`** ‚Äî forced by the ops' let-style catalogue bodies
    /// through `int.div`/`int.mod` (see `defs::int_ops::op_body`).
    FixedWidthCert((TermSpec, Vec<Lit>)) -> CoreProp = |(spec, args), _| {
        certs::fixed_width(&spec, &args)
            .and_then(|eq| seq(Ctx::new(), eq))
            .map_err(to_pure)
    }

    /// Closed literal (dis)equality certificate:
    /// `‚ä¢ IsThm(‚àÖ, ‚åú(a = b) = ‚åúa == b‚åù‚åù)` for two same-kind literals
    /// (`Bool`/`Nat`/`Int`/`SmallInt`/`Bytes`) ‚Äî equality AND disequality
    /// (`‚ä¢ (a = b) = F`) decided natively.
    ///
    /// ## Soundness
    ///
    /// The family contract above, resting on the kernel's literal
    /// denotational commitment: literals denote the standard values, and two
    /// same-kind literals are equal iff structurally equal (distinct
    /// literals denote distinct values ‚Äî what makes the `F` direction
    /// sound). Mixed kinds refuse.
    LitEqCert((Lit, Lit)) -> CoreProp = |(a, b), _| {
        certs::lit_eq(&a, &b)
            .and_then(|eq| seq(Ctx::new(), eq))
            .map_err(to_pure)
    }

    /// nat ‚Üî int / bytes coercion certificate for the canonical `nat.toInt`
    /// / `nat.toBytesLe` / `nat.toBytesBe` / `nat.fromBytesLe` /
    /// `nat.fromBytesBe` handles.
    ///
    /// ## Soundness
    ///
    /// The family contract above: each coercion on the literal denotations
    /// is the standard embedding / radix-256 (de)serialisation the catalogue
    /// op denotes.
    CoercionCert((TermSpec, Vec<Lit>)) -> CoreProp = |(spec, args), _| {
        certs::coercion(&spec, &args)
            .and_then(|eq| seq(Ctx::new(), eq))
            .map_err(to_pure)
    }

    /// The bit-level WASM float certificate (stage F2b), keyed by the
    /// canonical `defs::floats` registry: arithmetic / min-max / copysign /
    /// rounding / comparisons on `f32`/`f64` bit patterns (`f32.addBits :
    /// u32 ‚Üí u32 ‚Üí u32`, ‚Ä¶), `promoteBits`/`demoteBits`, and the saturating
    /// `truncSatBits`/`convertBits` int‚Üîfloat families at the WASM scalar
    /// tags `u32`/`u64`/`s32`/`s64`.
    ///
    /// ## Soundness
    ///
    /// The family contract above, with one difference from the other
    /// families: the bit-level float constants are **declaration-only**
    /// (`tm = None` ‚Äî no definitional body), so this certificate family is
    /// what pins their denotation. The contract: each constant denotes the
    /// corresponding **WASM deterministic-profile** operation *on bit
    /// patterns* ‚Äî a total function on `u32`/`u64` (arithmetic NaN results
    /// collapse to the single canonical NaN; `abs`/`neg`/`copysign` are pure
    /// bit ops preserving NaN payloads; `trunc_sat` saturates with NaN ‚Üí 0;
    /// comparisons follow IEEE 754 with `+0 = ‚àí0` and NaN unordered). Such a
    /// function exists (existence-without-construction: it is definable in
    /// HOL over the `u32`/`u64` carriers, bit by bit), and since the
    /// constants carry no other defining equations, interpreting them by it
    /// is conservative. The dispatch (`certs::float_bits`) computes exactly
    /// that function via the trusted `covalence-pure-trusted::float`
    /// `CanonRule`s ‚Äî the audited single NaN-canonicalization point, pinned
    /// bit-for-bit against wasmtime's deterministic profile by
    /// `covalence-pure-eval`'s differential suite ‚Äî so every minted equation
    /// is true under the pinned denotation. Every float body is total on bit
    /// patterns: the only refusals are shape refusals (wrong arity / wrong
    /// literal tag / non-canonical selector), never a wrong equation. The
    /// rule derives its whole conclusion from the input (selector + native
    /// args), so it is sound on ALL inputs.
    FloatCert((TermSpec, Vec<Lit>)) -> CoreProp = |(spec, args), _| {
        certs::float_bits(&spec, &args)
            .and_then(|eq| seq(Ctx::new(), eq))
            .map_err(to_pure)
    }
    }

    // CanonRule ops admitted for `covalence_pure::canon` under `CoreEval`
    // (soundness documented on each op ‚Äî see `crate::tohol_ops`).
    canon { HolApp }
}

// ============================================================================
// The EVAL_MANIFEST golden (eval-tier TCB budget): docs/deps/eval-manifest.txt
// ============================================================================

#[cfg(test)]
mod manifest_tests {
    use std::any::TypeId;
    use std::collections::HashSet;

    use covalence_pure::Language;

    use super::super::lang::CoreEval;
    use super::{EVAL_MANIFEST, eval_admits, eval_rule_names};

    const GOLDEN: &str = concat!(
        env!("CARGO_MANIFEST_DIR"),
        "/../../../../docs/deps/eval-manifest.txt"
    );

    /// The transitional literal-reify rule and the permanent structural
    /// (succ-tower) rules pin CONTRADICTORY denotations for `toHOL n` at the
    /// `Term` sort ‚Äî admitting both makes the base tier inconsistent (audit
    /// wave-1 finding: sym+trans would equate `Val(nat_lit 1)` with
    /// `Val(app(succ, nat_lit 0))`, a false definitional-Eq fact). This guard
    /// fires the moment both appear in the manifest: delete `ToHolNatVal` in
    /// the SAME commit that admits the structural rules. (Moved here from
    /// core with the rules ‚Äî stage E2.)
    #[test]
    fn tohol_unfolding_rules_are_exclusive() {
        let names = eval_rule_names();
        let transitional = names.iter().any(|(n, _)| *n == "ToHolNatVal");
        let structural = names
            .iter()
            .any(|(n, _)| n.starts_with("ToHolNatZero") || n.starts_with("ToHolNatSucc"));
        assert!(
            !(transitional && structural),
            "ToHolNatVal (literal denotation) and the structural succ-tower rules \
             must never be admitted together ‚Äî they pin contradictory `toHOL` \
             denotations (see SKELETONS.md)"
        );
    }

    #[test]
    fn manifest_matches_golden() {
        let names = eval_rule_names();

        // Structure: the manifest is CoreEval's own; its single parent is
        // CoreLang (whose manifest embeds Builtins in turn ‚Äî the full tower);
        // the name projection is 1:1 and in the same order.
        assert_eq!(EVAL_MANIFEST.ty, TypeId::of::<CoreEval>());
        assert_eq!(EVAL_MANIFEST.extends.len(), 1, "one parent: CoreLang");
        assert_eq!(
            EVAL_MANIFEST.extends[0].ty,
            TypeId::of::<covalence_core::seam::CoreLang>()
        );
        assert!(
            CoreEval.extends(TypeId::of::<covalence_core::seam::CoreLang>()),
            "extends() mirrors the manifest parent"
        );
        assert_eq!(names.len(), EVAL_MANIFEST.admits.len(), "1:1 projection");
        for ((name, ty), rec) in names.iter().zip(EVAL_MANIFEST.admits) {
            assert_eq!(*ty, rec.ty, "name/manifest order drift at {name}");
        }

        // Identity: no duplicates; direct admits ‚ü∫ manifest; the tier also
        // admits the inherited HOL rules (delegation) but no strangers.
        let mut tys = HashSet::new();
        for (name, ty) in &names {
            assert!(tys.insert(*ty), "duplicate rule TypeId for {name}");
            assert!(eval_admits(*ty), "manifest rule {name} not admitted");
            assert!(CoreEval.admits(*ty), "tier does not admit {name}");
        }
        assert!(!eval_admits(TypeId::of::<CoreEval>()));
        assert!(!eval_admits(TypeId::of::<covalence_pure_eval::NatAdd>()));
        assert!(!CoreEval.admits(TypeId::of::<covalence_pure_eval::NatAdd>()));

        // The golden.
        let ours: String = names.iter().map(|(n, _)| *n).collect::<Vec<_>>().join("\n") + "\n";
        if std::env::var_os("COV_REGEN_GOLDEN").is_some() {
            std::fs::write(GOLDEN, &ours).expect("write golden");
            return;
        }
        let golden = std::fs::read_to_string(GOLDEN)
            .expect("read docs/deps/eval-manifest.txt (regenerate with COV_REGEN_GOLDEN=1)");
        assert_eq!(
            golden, ours,
            "EVAL_MANIFEST drifted from docs/deps/eval-manifest.txt ‚Äî audit \
             the diff, then regenerate with COV_REGEN_GOLDEN=1"
        );
    }
}
